import { readFile } from "node:fs/promises"
import { join } from "node:path"

// Data layer for the model-centric views (homepage models section,
// /models/[slug], per-bench model lists). Reads public/data/models.json,
// which is regenerated by scripts/build_model_index.py on every publish.

export type Bench = "hard" | "mega" | "cuda"

export interface ModelCell {
  run_id: string | null
  correct: boolean
  score: number | null
  verdict: string
  valid: boolean
  elapsed_seconds?: number | null
  tok_s?: number | null
  ctx?: Record<string, number>
  framework?: string | null
  solution_url: string | null
  trace_url: string | null
}

export interface FlagEntry {
  run_id: string
  verdict: string
  summary: string
}

export interface GpuBlock {
  label: string | null
  harness: string | null
  effort: string | null
  passed: number
  total_problems: number
  perf: number | null
  cells: Record<string, ModelCell>
}

export interface BenchBlock extends GpuBlock {
  audited: number
  flagged: number
  flags: FlagEntry[]
  gpus: Record<string, GpuBlock>
}

export interface LegacyBlock {
  best_pass_count: number
  total_problems: number
  labels: string[]
}

export interface ModelEntry {
  slug: string
  name: string
  lab: string
  benches: Partial<Record<Bench, BenchBlock>>
  legacy: Record<string, LegacyBlock>
  totals: { audited: number; flagged: number }
}

export interface ModelIndex {
  generated: string
  benches: Record<
    string,
    {
      problems: string[]
      gpu: string
      gpus?: string[]
      gpu_labels?: Record<string, string>
    }
  >
  methodology: string
  models: ModelEntry[]
}

export const BENCH_LABELS: Record<Bench, string> = {
  hard: "Hard",
  mega: "Mega",
  cuda: "CUDA",
}

export const PROBLEM_LABELS: Record<string, string> = {
  "01_fp8_gemm": "FP8 GEMM",
  "02_kda_cutlass": "KDA CUTLASS",
  "03_paged_attention": "Paged Attention",
  "05_topk_bitonic": "TopK Bitonic",
  "06_sonic_moe_swiglu": "Sonic MoE",
  "07_w4a16_gemm": "W4A16 GEMM",
  "01_rl_grid_ppo": "RL Grid PPO",
  "02_kimi_linear_decode": "Kimi-Linear Decode",
  "01_glm52_fused_moe": "GLM-5.2 Fused MoE",
  "02_deepseek_nsa": "DeepSeek NSA",
  "03_megaqwen_decode": "MegaQwen Decode",
  "04_grid_mingru_sps": "Grid + MinGRU SPS",
  "01_rmsnorm_residual": "RMSNorm + Residual",
  "02_online_softmax": "Online Softmax",
}

export const FLAG_VERDICTS = new Set([
  "reward_hack",
  "contamination",
  "rubric_leak",
  "megakernel_not_authentic",
])

let cached: Promise<ModelIndex> | null = null

export function loadModelIndex(): Promise<ModelIndex> {
  cached ??= readFile(join(process.cwd(), "public/data/models.json"), "utf8").then(
    (raw) => JSON.parse(raw) as ModelIndex,
  )
  return cached
}

export function problemLabel(key: string): string {
  return PROBLEM_LABELS[key] ?? key.replace(/^\d+_/, "").replace(/_/g, " ")
}

export function benchValue(bench: Bench, score: number): string {
  return bench === "mega" ? `${score.toFixed(2)}x` : `${(score * 100).toFixed(1)}%`
}

export function auditChipClass(verdict: string): string {
  if (FLAG_VERDICTS.has(verdict)) return "audit-chip audit-chip-bad"
  if (verdict === "clean") return "audit-chip audit-chip-clean"
  if (verdict === "unaudited") return "audit-chip audit-chip-muted"
  return "audit-chip audit-chip-warn"
}

// ---- Ranked model-list views ------------------------------------------------

export interface ModelRow {
  slug: string
  name: string
  lab: string
  subtitle: string
  passed: number
  total: number
  perf: number | null
  audited: number
  flagged: number
  badges: { label: string; value: string; tone: "good" | "muted" }[]
  /** benches fully passed (index view); ignored by per-bench views */
  full: number
}

function harnessSubtitle(block: GpuBlock | null | undefined): string {
  if (!block) return ""
  return [block.harness, block.effort].filter(Boolean).join(" · ")
}

/** One row per model with a canonical board presence, ranked
 *  pass-rate desc -> passed desc -> perf desc (nulls last) -> slug. */
export function rowsForBench(
  index: ModelIndex,
  bench: Bench,
  gpu?: string,
): { board: ModelRow[]; sink: ModelRow[] } {
  const board: ModelRow[] = []
  const sink: ModelRow[] = []
  const gpuLabels = index.benches[bench]?.gpu_labels ?? {}
  for (const m of index.models) {
    const block = m.benches[bench]
    if (!block) continue
    const view: GpuBlock | undefined = gpu ? block.gpus?.[gpu] : block
    const onBoard = !!view && (view.passed > 0 || Object.keys(view.cells).length > 0)
    if (onBoard && view) {
      board.push({
        slug: m.slug,
        name: m.name,
        lab: m.lab,
        subtitle: harnessSubtitle(view),
        passed: view.passed,
        total: view.total_problems,
        perf: view.perf,
        audited: block.audited ?? 0,
        flagged: block.flagged ?? 0,
        badges: [],
        full: 0,
      })
      continue
    }
    // Sink view only exists on the canonical board (audits are bench-level,
    // not split per GPU).
    if (gpu) continue
    if ((block.audited ?? 0) === 0 && (block.flagged ?? 0) === 0) continue
    const gpuNotes = Object.entries(block.gpus ?? {})
      .filter(([, g]) => g.passed > 0)
      .map(([k, g]) => `${gpuLabels[k] ?? k}: ${g.passed}/${g.total_problems}`)
    sink.push({
      slug: m.slug,
      name: m.name,
      lab: m.lab,
      subtitle: gpuNotes.length ? `other boards: ${gpuNotes.join(" · ")}` : "",
      passed: 0,
      total: block.total_problems,
      perf: null,
      audited: block.audited ?? 0,
      flagged: block.flagged ?? 0,
      badges: [],
      full: 0,
    })
  }
  board.sort(compareRows)
  sink.sort((a, b) => a.slug.localeCompare(b.slug))
  return { board, sink }
}

export function compareRows(a: ModelRow, b: ModelRow): number {
  const ar = a.total > 0 ? a.passed / a.total : 0
  const br = b.total > 0 ? b.passed / b.total : 0
  if (br !== ar) return br - ar
  if (b.passed !== a.passed) return b.passed - a.passed
  const ap = a.perf ?? -1
  const bp = b.perf ?? -1
  if (bp !== ap) return bp - ap
  return a.slug.localeCompare(b.slug)
}

/** Homepage index view: rank by benches fully passed, then mean normalized
 *  perf across benches attempted; per-bench pass chips on every row. */
export function rowsForIndex(index: ModelIndex): { board: ModelRow[]; sink: ModelRow[] } {
  const benches: Bench[] = ["mega", "hard", "cuda"]
  const board: ModelRow[] = []
  const sink: ModelRow[] = []
  for (const m of index.models) {
    const attempted = benches.filter((b) => {
      const blk = m.benches[b]
      return blk && (blk.passed > 0 || Object.keys(blk.cells).length > 0)
    })
    if (attempted.length === 0) {
      if (m.totals.audited > 0 || m.totals.flagged > 0) {
        sink.push({ ...makeIndexRow(m, [], null), full: 0 })
      }
      continue
    }
    const full = attempted.filter((b) => {
      const blk = m.benches[b]!
      return blk.total_problems > 0 && blk.passed >= blk.total_problems
    }).length
    const perfs = attempted
      .map((b) => m.benches[b]!.perf)
      .filter((p): p is number => p != null)
    const meanPerf = perfs.length ? perfs.reduce((s, p) => s + p, 0) / perfs.length : null
    board.push({ ...makeIndexRow(m, attempted as Bench[], meanPerf), full })
  }
  board.sort((a, b) => {
    if (b.full !== a.full) return b.full - a.full
    const ap = a.perf ?? -1
    const bp = b.perf ?? -1
    if (bp !== ap) return bp - ap
    return a.slug.localeCompare(b.slug)
  })
  sink.sort((a, b) => a.slug.localeCompare(b.slug))
  return { board, sink }
}

function makeIndexRow(
  m: ModelEntry,
  attempted: Bench[],
  meanPerf: number | null,
): Omit<ModelRow, "full"> {
  const order: Bench[] = ["mega", "hard", "cuda"]
  const badges = order
    .filter((b) => attempted.includes(b))
    .map((b) => {
      const blk = m.benches[b]!
      const full = blk.total_problems > 0 && blk.passed >= blk.total_problems
      return {
        label: BENCH_LABELS[b].toUpperCase(),
        value: `${blk.passed}/${blk.total_problems}`,
        tone: full ? ("good" as const) : ("muted" as const),
      }
    })
  const totalPassed = attempted.reduce((s, b) => s + m.benches[b]!.passed, 0)
  const totalProblems = attempted.reduce((s, b) => s + m.benches[b]!.total_problems, 0)
  return {
    slug: m.slug,
    name: m.name,
    lab: m.lab,
    subtitle: "",
    passed: totalPassed,
    total: totalProblems,
    perf: meanPerf,
    audited: m.totals.audited,
    flagged: m.totals.flagged,
    badges,
  }
}
